import React, { type CSSProperties, type ReactNode } from 'react'

import type { RichTextDocument, RichTextInlineStyle, RichTextNode, RichTextRenderOptions } from '../types'
import clsx from 'clsx'

/**
 * 限制图片来源协议。
 *
 * React 会自动转义文本和属性，但不会替我们判断 URL 协议是否安全，所以这里仍然做白名单。
 */
const sanitizeImageSource = (value: string): string | null => {
  const normalized = value.trim()
  if (!normalized) {
    return null
  }

  if (/^https?:\/\//i.test(normalized)) {
    return normalized
  }

  if (/^data:image\/(?:png|jpe?g|gif|webp|avif);base64,[a-z0-9+/=]+$/i.test(normalized)) {
    return normalized
  }

  return null
}

/**
 * 富文本表情的默认排版。
 *
 * 这些规则属于 richtext 节点的渲染语义，不应该散落在各个平台模板里：
 * - 表情跟随当前文字大小缩放；
 * - 作为行内内容参与排版；
 * - 不撑破行高，也不突破当前文本块宽度。
 */
const getRichTextEmojiStyle = (scale: number = 1): CSSProperties => ({
  display: 'inline-block',
  height: `${1.5 * scale}em`,
  width: 'auto',
  verticalAlign: scale > 1 ? 'text-bottom' : 'middle',
  lineHeight: 1
})

/** 统一的搜索图标，避免 template 每次都自己重复拼 JSX。 */
const SearchKeywordIcon = ({ className }: { className?: string }) => {
  return (
    <span
      aria-hidden
      className={className}
      style={{
        display: 'inline-flex',
        verticalAlign: 'super',
        marginLeft: '0.08em',
        lineHeight: 1
      }}
    >
      <svg
        viewBox='0 0 24 24'
        width='0.72em'
        height='0.72em'
        fill='none'
        stroke='currentColor'
        strokeWidth={2}
        strokeLinecap='round'
        strokeLinejoin='round'
      >
        <circle cx='11' cy='11' r='7' />
        <path d='m20 20-3.5-3.5' />
      </svg>
    </span>
  )
}

