/**
 * 渲染带行内样式的文本节点。
 */
const renderStyledText = (
  text: string,
  style: RichTextInlineStyle | undefined,
  index: number
): ReactNode => {
  if (!style) {
    return text
  }

  const classNames: string[] = []
  if (style.bold) classNames.push('font-bold')
  if (style.italic) classNames.push('italic')
  if (style.strike) classNames.push('line-through')

  const inlineStyle: CSSProperties = {}
  if (style.color) {
    inlineStyle.color = style.color
  }

  if (style.link) {
    return (
      <a
        key={`text-${index}`}
        href={style.link}
        className={classNames.join(' ') || undefined}
        style={inlineStyle}
        target='_blank'
        rel='noopener noreferrer'
        data-richtext-node='text'
      >
        {text}
      </a>
    )
  }

  if (classNames.length === 0 && Object.keys(inlineStyle).length === 0) {
    return text
  }

  return (
    <span
      key={`text-${index}`}
      className={classNames.join(' ') || undefined}
      style={inlineStyle}
      data-richtext-node='text'
    >
      {text}
    </span>
  )
}

/**
 * 将单个富文本节点渲染成 React 节点。
 *
 * 这里的设计重点是"只在 template 侧落地 UI 语义"：
 * - `core` 不需要依赖 React，也不用承担 JSX/SSR 运行时边界。
 * - React 负责文本与属性转义，我们只补上图片协议白名单。
 */
const renderNodeToReact = (
  node: RichTextNode,
  index: number,
  options: RichTextRenderOptions
): ReactNode => {
  switch (node.type) {
    case 'text':
      return renderStyledText(node.text, node.style, index)

    case 'lineBreak':
      return <br key={`br-${index}`} />

    case 'mention':
      return (
        <span
          key={`mention-${index}`}
          className={options.mention?.className}
          data-richtext-node='mention'
          data-user-id={node.userId}
        >
          {node.text}
        </span>
      )

    case 'searchKeyword':
      return (
        <span
          key={`search-${index}`}
          className={options.searchKeyword?.className}
          data-richtext-node='searchKeyword'
          data-search-query-id={node.queryId}
        >
          <span>{node.text}</span>
          <SearchKeywordIcon className={options.searchKeyword?.iconClassName} />
        </span>
      )

    case 'emoji': {
      const safeSrc = sanitizeImageSource(node.src)
      if (!safeSrc) {
        return node.name
      }

      return (
        <img
          key={`emoji-${index}`}
          className='mx-1'
          src={safeSrc}
          alt={node.name}
          style={getRichTextEmojiStyle(node.scale)}
          referrerPolicy='no-referrer'
          crossOrigin='anonymous'
          data-richtext-node='emoji'
        />
      )
    }

    case 'topic':
      return (
        <span
          key={`topic-${index}`}
          className={options.topic?.className}
          data-richtext-node='topic'
        >
          <span style={options.iconScale && options.iconScale !== 1 ? { transform: `scale(${options.iconScale})`, transformOrigin: 'left center', display: 'inline-block' } : undefined}>
            <TopicIcon />
          </span>
          {node.text}
        </span>
      )

    case 'at':
      return (
        <span
          key={`at-${index}`}
          className={options.at?.className}
          data-richtext-node='at'
          data-user-id={node.userId}
        >
          {node.text}
        </span>
      )

    case 'lottery':
      return (
        <span
          key={`lottery-${index}`}
          className={options.lottery?.className}
          data-richtext-node='lottery'
        >
          <span style={options.iconScale && options.iconScale !== 1 ? { transform: `scale(${options.iconScale})`, transformOrigin: 'left center', display: 'inline-block' } : undefined}>
            <LotteryIcon />
          </span>
          {node.text}
        </span>
      )

    case 'webLink':
      return (
        <a
          key={`weblink-${index}`}
          className={options.webLink?.className}
          href={node.jumpUrl}
          target='_blank'
          rel='noopener noreferrer'
          data-richtext-node='webLink'
        >
          <span style={options.iconScale && options.iconScale !== 1 ? { transform: `scale(${options.iconScale})`, transformOrigin: 'left center', display: 'inline-block' } : undefined}>
            <WebLinkIcon />
          </span>
          {node.text}
        </a>
      )

    case 'vote':
      return (
        <span
          key={`vote-${index}`}
          className={options.vote?.className}
          data-richtext-node='vote'
        >
          <span style={options.iconScale && options.iconScale !== 1 ? { transform: `scale(${options.iconScale})`, transformOrigin: 'left center', display: 'inline-block' } : undefined}>
            <VoteIcon />
          </span>
          {node.text}
        </span>
      )

    case 'viewPicture':
      return (
        <span
          key={`viewpicture-${index}`}
          className={options.viewPicture?.className}
          data-richtext-node='viewPicture'
        >
          <span style={options.iconScale && options.iconScale !== 1 ? { transform: `scale(${options.iconScale})`, transformOrigin: 'left center', display: 'inline-block' } : undefined}>
            <ViewPictureIcon />
          </span>
          {node.text}
        </span>
      )

    case 'heading': {
      const HeadingTag = `h${node.level}` as keyof React.JSX.IntrinsicElements
      return (
        <HeadingTag
          key={`heading-${index}`}
          data-richtext-node='heading'
          data-heading-level={node.level}
        >
          {node.nodes.map((child, childIndex) => renderNodeToReact(child, childIndex, options))}
        </HeadingTag>
      )
    }

    case 'paragraph':
      return (
        <p
          key={`paragraph-${index}`}
          data-richtext-node='paragraph'
        >
          {node.nodes.map((child, childIndex) => renderNodeToReact(child, childIndex, options))}
        </p>
      )

    case 'image': {
      const safeSrc = sanitizeImageSource(node.src)
      if (!safeSrc) {
        return null
      }
      return (
        <img
          key={`image-${index}`}
          src={safeSrc}
          alt={node.alt || ''}
          referrerPolicy='no-referrer'
          crossOrigin='anonymous'
          data-richtext-node='image'
        />
      )
    }

    case 'blockquote':
      return (
        <blockquote
          key={`blockquote-${index}`}
          data-richtext-node='blockquote'
        >
          {node.nodes.map((child, childIndex) => renderNodeToReact(child, childIndex, options))}
        </blockquote>
      )

    case 'list': {
      const ListTag = node.ordered ? 'ol' : 'ul'
      return (
        <ListTag
          key={`list-${index}`}
          data-richtext-node='list'
          data-list-ordered={node.ordered}
        >
          {node.items.map((item, itemIndex) => renderNodeToReact(item, itemIndex, options))}
        </ListTag>
      )
    }

    case 'listItem':
      return (
        <li
          key={`listitem-${index}`}
          data-richtext-node='listItem'
        >
          {node.nodes.map((child, childIndex) => renderNodeToReact(child, childIndex, options))}
        </li>
      )

    default:
      return null
  }
}

/**
 * 将富文本文档渲染成 React 节点。
 *
 * 这是 React 模板的首选渲染方式：
 * - 不经过 HTML 字符串；
 * - 不需要 `dangerouslySetInnerHTML`；
 * - 更适合 SSR，因为传输边界仍然是纯 JSON。
 */
export const renderRichTextToReact = (
  document: RichTextDocument,
  options: RichTextRenderOptions = {}
): ReactNode => {
  return (
    <>
      {document.nodes.map((node, index) => renderNodeToReact(node, index, options))}
    </>
  )
}
